import React from 'react';

function Login({ onLogin }) {
  const loginAs = (role) => {
    const userData = { role, name: role.charAt(0).toUpperCase() + role.slice(1) };
    localStorage.setItem('agriUser', JSON.stringify(userData));
    onLogin(userData);
  };

  return (
    <div style={{ textAlign: 'center', padding: '50px', backgroundColor: '#f4f7f2', minHeight: '100vh' }}>
      <h1>Welcome to Agri-AI</h1>
      <p>Select your account type to enter the marketplace</p>

      <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', marginTop: '30px' }}>
        {/* Buyer Card */}
        <div onClick={() => loginAs('buyer')} style={cardStyle}>
          <h2>🛒 Buyer</h2>
          <p>I want to buy fresh produce and see AI price predictions.</p>
        </div>

        {/* Seller Card */}
        <div onClick={() => loginAs('seller')} style={cardStyle}>
          <h2>🚜 Seller</h2>
          <p>I want to list my crops and optimize my profit margins.</p>
        </div>
      </div>
    </div>
  );
}

const cardStyle = {
  width: '250px',
  padding: '20px',
  border: '2px solid #2d5a27',
  borderRadius: '15px',
  cursor: 'pointer',
  backgroundColor: 'white',
  transition: '0.3s',
  boxShadow: '0 4px 8px rgba(0,0,0,0.1)'
};

export default Login;
